<script setup lang="ts">
import { ref, computed, onMounted, watch } from 'vue'
import { useStore } from 'vuex'
import { useRouter } from 'vue-router'
import axios from 'axios'

const store = useStore()
const router = useRouter()

// State
const notices = ref<any[]>([])
const currentNoticeIdx = ref(0)
const stats = ref({ lostWeekly: 32, claimedWeekly: 15 }) // Mock for now, replace with API if available
const activeTab = ref('lost')
const lostItems = ref<any[]>([])
const foundItems = ref<any[]>([])
const matches = ref<any[]>([]) // Mock
const hotLocations = ref<any>({ '图书馆': 12, '二食堂': 8, '操场': 5 }) // Mock
const faqs = ref([
  { q: '发布信息审核需要多久？', a: '通常在提交后1小时内完成审核。', open: false },
  { q: '认领物品需要带什么？', a: '请携带学生证或身份证进行线下核验。', open: false },
  { q: '如何撤销已发布的物品？', a: '在个人中心找到对应记录点击删除即可。', open: false }
])

// Computed
const isLoggedIn = computed(() => !!store.state.auth.token)
const user = computed(() => store.state.auth.user || {})
const isAdmin = computed(() => ['ROLE_ADMIN', 'ROLE_MANAGER'].includes(user.value.role))
const currentNotice = computed(() => notices.value[currentNoticeIdx.value])
const currentItems = computed(() => activeTab.value === 'lost' ? lostItems.value : foundItems.value)

// Methods
const fetchNotices = async () => {
  try {
    const res = await axios.get('/api/notice/list')
    notices.value = res.data || []
    if (notices.value.length === 0) {
      notices.value = [{ id: 1, title: '欢迎使用失物招领系统', content: '请大家积极发布失物与拾物信息，共同维护校园环境。' }]
    }
  } catch (e) {
    console.error(e)
    notices.value = [{ id: 1, title: '欢迎使用失物招领系统', content: '请大家积极发布失物与拾物信息，共同维护校园环境。' }]
  }
}

const fetchItems = async () => {
  try {
    const resLost = await axios.get('/api/lost/query?page=0&size=6')
    lostItems.value = resLost.data.records
    
    // Attempt to fetch found items if API exists, else mock
    try {
      const resFound = await axios.get('/api/found/query?page=0&size=6')
      foundItems.value = resFound.data.records
    } catch (e) {
      console.warn('Found API not ready yet')
    }
  } catch (e) {
    console.error(e)
  }
}

const statusText = (status: string) => {
  const map: any = { 'PENDING': '待审核', 'APPROVED': '待认领', 'CLAIMED': '已认领' }
  return map[status] || status
}

const formatDate = (ts: string) => {
  return new Date(ts).toLocaleDateString()
}

const viewDetail = (item: any) => {
  // TODO: Navigate to detail page
  console.log('View', item)
}

const searchByLocation = (loc: string) => {
  router.push({ path: '/query', query: { location: loc, keyword: loc } })
}

// Lifecycle
onMounted(() => {
  fetchNotices()
  fetchItems()
  // Auto rotate notices
  setInterval(() => {
    if (notices.value.length > 1) {
      currentNoticeIdx.value = (currentNoticeIdx.value + 1) % notices.value.length
    }
  }, 5000)
})
</script>

